import{n as e,t}from"./en-BeAvWqrp.js";import{t as n}from"./merge-9Qs9NaoX.js";var r=n(t,{auth:{nav:{signIn:`Logga in`,createAccount:`Skapa konto`,mobileTagline:`En smidig kopierare för varje Telegram-signal`,backHome:`Tillbaka till startsidan`},oauth:{continueWithGoogle:`Fortsätt med Google`,orDivider:`eller`},login:{heading:`Logga in på TScopier`,noAccount:`Har du inget konto?`,signUpLink:`Registrera dig`,footerPrompt:`Ny på TScopier?`,footerLink:`Skapa ett gratis konto`,email:`E-post`,emailPlaceholder:`du@exempel.se`,password:`Lösenord`,passwordPlaceholder:`Ange ditt lösenord`,forgotPassword:`Glömt lösenord?`,passwordResetSuccess:`Ditt lösenord har uppdaterats. Du kan logga in nu.`,submit:`Logga in`},forgotPassword:{heading:`Återställ lösenord`,subtitle:`Ange e-postadressen för ditt konto. Om den finns skickar vi en länk för att återställa lösenordet.`,email:`E-post`,emailPlaceholder:`du@exempel.se`,submit:`Skicka återställningslänk`,sentHeading:`Kontrollera din e-post`,sentSubtitle:`Om ett konto finns för {email} får du snart en länk för att återställa lösenordet.`,sentHint:`Kontrollera skräpposten om du inte ser meddelandet inom några minuter.`,backToLogin:`Tillbaka till inloggning`},resetPassword:{heading:`Välj ett nytt lösenord`,subtitle:`Ange och bekräfta ditt nya lösenord nedan.`,password:`Nytt lösenord`,passwordPlaceholder:`Ange ett nytt lösenord`,confirmPassword:`Bekräfta lösenord`,confirmPasswordPlaceholder:`Ange lösenordet igen`,passwordHint:`Minst 6 tecken`,passwordTooShort:`Lösenordet måste vara minst 6 tecken`,passwordMismatch:`Lösenorden matchar inte`,submit:`Uppdatera lösenord`,invalidHeading:`Länken har gått ut eller är ogiltig`,invalidSubtitle:`Denna återställningslänk är inte längre giltig. Begär en ny för att fortsätta.`,requestNewLink:`Begär ny länk`,backToLogin:`Tillbaka till inloggning`},signup:{heading:`Skapa ditt konto`,hasAccount:`Har du redan ett konto?`,signInLink:`Logga in`,footerPrompt:`Har du redan ett konto?`,footerLink:`Logga in`,firstName:`Förnamn`,firstNamePlaceholder:`Förnamn`,lastName:`Efternamn`,lastNamePlaceholder:`Efternamn`,email:`E-post`,emailPlaceholder:`du@exempel.se`,password:`Lösenord`,passwordPlaceholder:`Välj ett lösenord`,confirmPassword:`Bekräfta lösenord`,confirmPasswordPlaceholder:`Ange lösenordet igen`,passwordHint:`Minst 6 tecken`,passwordTooShort:`Lösenordet måste vara minst 6 tecken`,passwordMismatch:`Lösenorden matchar inte`,submit:`Skapa konto`,terms:{prefix:`Genom att registrera dig godkänner du våra`,termsOfService:`Användarvillkor`,conjunction:` och `,privacyPolicy:`Integritetspolicy`}},verify:{heading:`Kontrollera din e-post`,subtitle:`Vi har precis skickat en verifieringslänk till {email}.`,resend:`Skicka igen`,resent:`E-post skickad!`,backToLogin:`Tillbaka till inloggning`},marketing:{headline:`En smidig kopierare för varje Telegram-signal`,trustpilotLabel:`Trustpilot`,reviews:e,copyright:`© {year} Tartarix Inc.`},language:{label:`Språk`,choose:`Välj språk`,searchPlaceholder:`Sök språk…`,noResults:`Inga språk hittades`},theme:{light:`Ljust läge`,dark:`Mörkt läge`,switchToLight:`Byt till ljust läge`,switchToDark:`Byt till mörkt läge`}},contactSupportPage:{channelsTitle:`Hur kan vi hjälpa dig?`,channelsSubtitle:`Kontakta TSCopier-teamet via e-post, läs dokumentationen eller starta en livechatt.`,email:{title:`Support via e-post`,description:`Skicka frågor om konto, fakturering eller copier - vi svarar vanligtvis inom en arbetsdag.`,cta:`Skicka e-post`},docs:{title:`Dokumentation`,description:`Steg-för-steg-guider för att koppla mäklare, Telegram-kanaler, handelsstilar och felsökning.`,cta:`Öppna dokumentation`},liveChat:{title:`Livechatt`,description:`Chatta med oss i realtid för snabb installationshjälp medan du är i instrumentpanelen.`,cta:`Starta livechatt`},faq:{title:`Vanliga frågor`,subtitle:`Snabba svar innan du kontaktar oss.`,items:[{question:`Hur kopplar jag mitt MetaTrader-konto?`,answer:`Öppna Konfiguration, lägg till ett mäklarkonto, ange dina MetaTrader-inloggningsuppgifter och vänta tills anslutningsstatus visar ansluten. Varje länkat konto måste ha handelsstil, lotstorlek och kanalval sparat innan kopieringen startar.`},{question:`Varför kopieras inte mina Telegram-signaler?`,answer:`Kontrollera att mäklaren är ansluten, att Telegram-kanalen är länkad och aktiv, att kanalen är vald på mäklaren i Konfiguration, att din prenumeration är aktiv och att din e-post är verifierad. Granska Copier Logs för orsaker till att signaler hoppas över, till exempel kanalfilter, nyhetsblockering eller saknad SL/TP i signalen.`},{question:`Hur lägger jag till en Telegram-signal-kanal?`,answer:`Gå till Kanaler, anslut Telegram vid behov och lägg sedan till kanalens användarnamn eller inbjudningslänk. Aktivera kanalen och tilldela den till de mäklarkonton som ska kopiera signalerna i Konfiguration.`},{question:`Vad gör nyhetshandel / blackout i ekonomisk kalender?`,answer:`När nyhetshandel är inaktiverad på ett konto kan TSCopier pausa nya positioner och valfritt stänga öppna affärer runt kalenderhändelser med hög påverkan. Använd sidan Ekonomisk kalender för att se kommande publiceringar och konfigurera regler under Kontokonfiguration.`},{question:`Behövs en betald prenumeration för att kopiera affärer?`,answer:`En aktiv betald plan krävs för livekörning av Telegram-copier. Du kan fortfarande utforska instrumentpanelen och konfigurationen under en tillgänglig testperiod; kontrollera Fakturering för aktuell plan och förnyelsestatus.`},{question:`Varför måste jag verifiera min e-post innan jag använder plattformen?`,answer:`E-postverifiering bekräftar din inloggning och gör att vi kan skicka kvitton och viktiga kontovarningar. Om du fastnar på verifieringsskärmen kan du använda länken för att skicka om eller kontakta support med adressen du registrerade dig med.`},{question:`Min mäklare visas som frånkopplad - vad ska jag prova?`,answer:`Bekräfta att MetaTrader kör hos din mäklare, att inloggningsuppgifterna fortfarande är giltiga och att kontot inte är låst. Uppdatera från Konfiguration och kontrollera sedan Copier Logs för sessionsfel. Om problemet kvarstår, mejla support och ange mäklarens namn och kontologin (aldrig ditt lösenord).`},{question:`Kan jag kopiera samma kanal till flera maklare?`,answer:`Ja. Länka varje MetaTrader-konto separat i Konfiguration och välj samma Telegram-kanal för varje mäklare. Lotstorlek, handelsstil och riskinställningar anges per konto.`}]}},riskDisclaimerPage:{title:`Riskvarning`,intro:`Handel med valuta, CFD:er och andra belånade produkter innebär en betydande risk för förlust. TSCopier är ett verktyg för kopiering av affärer — inte en mäklare, investeringsrådgivare eller finansiell planerare. Ingenting på denna sida utgör finansiell rådgivning. Du är ensam ansvarig för dina handelsbeslut och eventuella förluster.`,sections:[{title:`Allmän handelsrisk`,paragraphs:[`Du kan förlora delar av eller hela ditt insatta kapital. Hävstång förstorar både vinster och förluster. Tidigare resultat för en signalleverantör, ett backtest eller din egen historik garanterar inte framtida resultat.`,`Marknader kan gappa, stoppas eller röra sig kraftigt vid nyhetshändelser. TSCopier garanterar inte att signaler tas emot, tolkas eller exekveras till ett visst pris eller vid en viss tidpunkt.`]},{title:`Risk hos signalleverantör`,paragraphs:[`Kopiera endast signalleverantörer som du litar på och förstår. Leverantörer kan ha incitament som strider mot dina intressen. Marknadsföringsbilder, påståenden om vinstfrekvens och selekterade resultat kanske inte speglar vad du upplever på ditt konto, med din lotstorlek, din mäklare eller din latens.`,`Verifiera resultat oberoende när det är möjligt. En leverantör som fungerar för andra kan ändå vara olämplig för din risktolerans, kontostorlek eller handelstider.`]},{title:`Repainting och kanalmanipulation`,paragraphs:[`Vissa Telegram-kanaler för signaler redigerar eller tar bort meddelanden efter en misslyckad affär så att den publika feeden ser felfri ut. En "lyckad" signal kan ha skrivits om, och en förlorande signal kan försvinna helt.`,`Förlita dig inte enbart på kanalens synliga historik eller skärmbilder från tredje part. Jämför med dina egna Copier Logs, mäklarutdrag och tidsstämplade poster. Repainting gör det lätt för leverantörer att framstå som mer precisa än de faktiskt är.`]},{title:`Begränsningar i tolkning och exekvering`,paragraphs:[`Signaler tolkas automatiskt från text. Skrivfel i stop loss (SL) eller take profit (TP) — fel siffror, saknade decimaler, tvetydiga symboler eller blandade enheter — kan ge ogiltiga priser. TSCopier kan hoppa över signalen, ignorera ogiltiga nivåer eller använda standardvärden från din konfiguration i stället för leverantörens avsikt.`,`Exekveringen kan skilja sig från leverantörens ingång: slippage, requotes, partiella fyllningar, regler om minsta avstånd och avbrutna brokersessioner påverkar utfallet. Strict entry, range pending och multi-leg-stilar ökar komplexiteten ytterligare. Kontrollera alltid öppna positioner hos din mäklare.`]},{title:`Operativa risker och konfigurationsrisker`,paragraphs:[`Nyhetsblackouts, kanalfilter, vinstmål, maxförlustgränser, prenumerationsstatus och inställningar per kanal kan blockera eller ändra kopieringen. Felkonfigurerad lotstorlek, symbolmappning eller ej länkade kanaler är vanliga orsaker till att affärer inte kopieras som förväntat.`,`Automatisk stängning när gränser uppnås stänger kanalattribuerade affärer på TSCopiers sida, men kan inte återställa en marknadsförlust som redan uppstått. Konfigurationsändringar gäller efter att de sparats — osparade utkast skyddar inte ditt konto.`]},{title:`Var aktiv under kopiering`,paragraphs:[`Automatisk kopiering är inte "ställ in och glöm". Övervaka öppna affärer, equity, margin och Copier Logs regelbundet. Ingrip hos din mäklare när förhållanden ändras eller när du inte längre accepterar leverantörens exponering.`,`Om du inte kan övervaka ditt konto aktivt kan kopiering av livesignaler vara olämpligt för dig.`]},{title:`Förbättra dina chanser (inte rådgivning)`,paragraphs:[`Börja med ett demokonto eller minsta möjliga live-storlek som du har råd att förlora. Utvärdera kanaler över tid; använd backtester där det finns; aktivera maxförlust och vinstmål; finjustera kanalfilter; diversifiera mellan leverantörer i stället för att koncentrera risken.`,`Läs orsaker till att signaler hoppas över i Copier Logs när affärer inte tas. Ha realistiska förväntningar — konsekventa små fördelar med strikt riskkontroll är något helt annat än marknadsföring om att "bli rik snabbt".`]}],closing:`Genom att använda TSCopier bekräftar du att handel är riskfylld, att signalleverantörer kan vara opålitliga eller vilseledande, och att du accepterar fullt ansvar för alla affärer som placeras på dina länkade konton.`}});export{r as sv};